    ) -> None:
        from erk_slack_bot.app import create_app

        settings = Settings(SLACK_BOT_TOKEN="xoxb-token", SLACK_APP_TOKEN="xapp-token")
        result = create_app(settings=settings)

        mock_app_cls.assert_called_once_with(token="xoxb-token")
